function returnInput(input) {
  return input;
}

console.log(returnInput(5));  // console.logで '5' を表示

function add(a, b) {
  return a + b;
}

console.log(add(5, 3));  // console.logで '8' を表示

function isOdd(num) {
  if (num % 2 == 1) {
    return true;
  } else {
    return false;
  }
}

console.log(isOdd(5));  // console.logで 'true' を表示
console.log(isOdd(4));  // console.logで 'false' を表示

function returnString(inputString) {
  return inputString;
}

console.log(returnString('Hello, World!'));  // console.logで 'Hello, World!' を表示

function concatenateStrings(string1, string2) {
  return string1 + string2;
}

console.log(concatenateStrings('Hello, ', 'World!'));  // console.logで 'Hello, World!' を表示

function multiplyNumbers(num1, num2) {
  return num1 * num2;
}

console.log(multiplyNumbers(3, 4));  // console.logで 12 を表示

function sumAndDifference(num1, num2) {
  return [num1 + num2, num1 - num2];
}

console.log(sumAndDifference(7, 5));  // console.logで [12, 2] を表示

function concatStrings(str1, str2) {
  return str1 + str2;
}

console.log(concatStrings('Hello, ', 'world!'));  // console.logで 'Hello, world!' を表示

function isEven(num) {
  return num % 2 === 0;
}

console.log(isEven(3));  // console.logで false を表示
console.log(isEven(4));  // console.logで true を表示

function arrayLength(arr) {
  return arr.length;
}

console.log(arrayLength([1, 2, 3, 4, 5]));  // console.logで 5 を表示

function toUpperCase(str) {
  return str.toUpperCase();
}

console.log(toUpperCase('hello'));  // console.logで 'HELLO' を表示

function joinElements(arr) {
  return arr.join('');
}

console.log(joinElements(['H', 'e', 'l', 'l', 'o']));  // console.logで 'Hello' を表示

function maxOfArray(arr) {
  return Math.max(...arr);
}

console.log(maxOfArray([1, 2, 3, 4, 5]));  // console.logで 5 を表示

function minOfArray(arr) {
  return Math.min(...arr);
}

console.log(minOfArray([1, 2, 3, 4, 5]));  // console.logで 1 を表示

function stringLength(str) {
  return str.length;
}

console.log(stringLength('Hello World!'));  // console.logで 12 を表示

function power(base, exponent) {
  return Math.pow(base, exponent);
}

console.log(power(2, 3));  // console.logで 8 を表示

function sumOfArray(arr) {
  return arr.reduce((total, current) => total + current, 0);
}

console.log(sumOfArray([1, 2, 3, 4, 5]));  // console.logで 15 を表示

function averageOfArray(arr) {
  var total = arr.reduce((total, current) => total + current, 0);
  return total / arr.length;
}

console.log(averageOfArray([1, 2, 3, 4, 5]));  // console.logで 3 を表示

function reverseString(str) {
  return str.split('').reverse().join('');
}

console.log(reverseString('hello'));  // console.logで 'olleh' を表示

function evaluateNumber(n) {
  return n % 2 === 0 ? 'Even' : 'Odd';
}

console.log(evaluateNumber(5));  // console.logで 'Odd' を表示
